(function(){const KEY='sofatelcom_modern_ui_v1';function applyModernIfEnabled(){try{const val=localStorage.getItem(KEY);const disabled=val==='0';if(!disabled&&document.body)document.body.classList.add('modern');}catch(e){if(document.body)document.body.classList.add('modern');}}function enableModernUI(){try{localStorage.setItem(KEY,'1');}catch(e){}if(document.body)document.body.classList.add('modern');}function disableModernUI(){try{localStorage.setItem(KEY,'0');}catch(e){}if(document.body)document.body.classList.remove('modern');}function toggleModernUI(){if(document.body&&document.body.classList.contains('modern'))disableModernUI();else enableModernUI();}window.enableModernUI=enableModernUI;window.disableModernUI=disableModernUI;window.toggleModernUI=toggleModernUI;applyModernIfEnabled();})();